name="prakash"
length=len(name) # This will calculate the length of the string
print(length)
print(name.endswith("ash")) # This will check if the string ends with "ash"
print(name.startswith("pr")) # This will check if the string starts with "pr"
print(name.capitalize()) # This will capitalize the first character of the string
print(name.upper()) # This will convert the string to uppercase

lun="Babar is a good good boy"
print(lun.replace("good","bad",2)) # This will replace the first 2 occurrences of "good" with "bad"
print(lun.split()) # This will split the string into a list of words    